mapper.select:
SELECT id, stage_id AS stageId, paper, title, exam_year AS examYear, task,
       word_count_min AS wordCountMin, word_count_max AS wordCountMax,
       max_score AS maxScore, source, is_active AS isActive, updated_at AS updatedAt
FROM essay_prompt
WHERE 1 = 1
  AND stage_id = #{stageId}
  AND exam_year = #{examYear}
  AND task = #{task}
  AND is_active = 10

    AND (
      paper LIKE CONCAT('%', #{keyword}, '%')
      OR title LIKE CONCAT('%', #{keyword}, '%')
      OR prompt_text LIKE CONCAT('%', #{keyword}, '%')
    )

ORDER BY updated_at DESC, id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM essay_prompt
WHERE 1 = 1
  AND stage_id = #{stageId}
  AND exam_year = #{examYear}
  AND task = #{task}
  AND is_active = 10

    AND (
      paper LIKE CONCAT('%', #{keyword}, '%')
      OR title LIKE CONCAT('%', #{keyword}, '%')
      OR prompt_text LIKE CONCAT('%', #{keyword}, '%')
    )
